mapper.select:
SELECT a.BBS_ID, a.BBS_TY_CODE, b.CODE_NM as BBS_TY_CODE_NM, a.BBS_NM, a.TMPLAT_ID, a.USE_AT, DATE_FORMAT(a.FRST_REGIST_PNTTM, '%Y-%m-%d') as FRST_REGIST_PNTTM, d.USER_NM AS FRST_REGISTER_NM FROM bbs_mst a LEFT OUTER JOIN (SELECT CODE_ID, CODE, CODE_NM FROM code_sub WHERE CODE_ID = 'COM101' AND USE_AT='Y') b ON a.BBS_TY_CODE = b.CODE LEFT OUTER JOIN (SELECT EMPLYR_ID, USER_NM FROM member_mst) d ON a.FRST_REGISTER_ID = d.EMPLYR_ID WHERE 1=1 AND a.BBS_NM LIKE CONCAT ('%', #{searchWrd},'%')
AND a.BBS_INTRCN LIKE CONCAT ('%', #{searchWrd},'%')
ORDER BY a.FRST_REGIST_PNTTM DESC LIMIT #{recordCountPerPage} OFFSET #{firstIndex}
